164→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
165→        require(elementType == VALUE_PARAMETER_LIST)
166→        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
167→    }
