169→    private fun ASTNode.containsAnnotatedParameter(): Boolean {
170→        require(elementType == VALUE_PARAMETER_LIST)
171→        return this.children()
172→            .filter { it.elementType == VALUE_PARAMETER }
173→            .any { it.isAnnotated() }
174→    }
175→
176→    private fun ASTNode.isAnnotated() =
177→        findChildByType(ElementType.MODIFIER_LIST)
178→            ?.children()
179→            .orEmpty()
180→            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
