182→    private fun wrapParameterList(
183→        node: ASTNode,
184→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
185→        autoCorrect: Boolean,
186→    ) {
187→        node
188→            .children()
189→            .forEach { child -> wrapParameterInList(child, emit, autoCorrect) }
190→    }
