192→    private fun intendedIndent(child: ASTNode): String =
193→        when {
194→            // IDEA quirk:
195→            // fun <
196→            //     T,
197→            //     R> test(
198→            //     param1: T
199→            //     param2: R
200→            // )
201→            // instead of
202→            // fun <
203→            //     T,
204→            //     R> test(
205→            //         param1: T
206→            //         param2: R
207→            //     )
208→            child.treeParent.hasTypeParameterListInFront() -> -1
209→
210→            else -> 0
211→        }.let {
212→            if (child.elementType == VALUE_PARAMETER) {
213→                it + 1
214→            } else {
215→                it
216→            }
217→        }.let { indentLevelFix ->
218→            val indentLevel =
219→                indentConfig
220→                    .indentLevelFrom(child.treeParent.indent(false))
221→                    .plus(indentLevelFix)
222→            "\n" + indentConfig.indent.repeat(indentLevel)
223→        }
