225→    private fun wrapParameterInList(
226→        child: ASTNode,
227→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
228→        autoCorrect: Boolean,
229→    ) {
230→        when (child.elementType) {
231→            LPAR -> {
232→                val prevLeaf = child.prevLeaf()
233→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
234→                    emit(child.startOffset, errorMessage(child), true)
235→                    if (autoCorrect) {
236→                        prevLeaf.delete()
237→                    }
238→                }
239→            }
240→            VALUE_PARAMETER,
241→            RPAR,
242→            -> {
243→                // aiming for
244→                // ... LPAR
245→                // <line indent + indentSize> VALUE_PARAMETER...
246→                // <line indent> RPAR
247→                val intendedIndent = intendedIndent(child)
248→                val prevLeaf = child.prevLeaf()
249→                if (prevLeaf is PsiWhiteSpace) {
250→                    if (prevLeaf.getText().contains("\n")) {
251→                        // The current child is already wrapped to a new line. Checking and fixing the
252→                        // correct size of the indent is the responsibility of the IndentationRule.
253→                        return
254→                    } else {
255→                        // The current child needs to be wrapped to a newline.
256→                        emit(child.startOffset, errorMessage(child), true)
257→                        if (autoCorrect) {
258→                            // The indentation is purely based on the previous leaf only. Note that in
259→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
260→                            // determines the final indentation. But if the indent rule is disabled then the
261→                            // indent of this rule is kept.
262→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
263→                        }
264→                    }
265→                } else {
266→                    // Insert a new whitespace element in order to wrap the current child to a new line.
267→                    emit(child.startOffset, errorMessage(child), true)
268→                    if (autoCorrect) {
269→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
270→                    }
271→                }
272→                // Indentation of child nodes need to be fixed by the IndentationRule.
273→            }
274→        }
275→    }
