288→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
289→        val parent = this.treeParent
290→        val typeParameterList =
291→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
292→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
293→            } else {
294→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
295→            }
296→        val typeListNode =
297→            typeParameterList
298→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
299→                ?: return false
300→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
