150→            .let { startOfFunctionLiteral ->
151→                treeParent
152→                    ?.takeIf { it.elementType == FUNCTION_LITERAL }
153→                    ?.prevCodeLeaf()
154→                    ?.takeIf { it.treeParent.elementType == ElementType.VALUE_ARGUMENT_LIST }
155→                    ?.takeIf { it.treeParent.treeParent.elementType == ElementType.CALL_EXPRESSION }
156→                    ?.leaves()
157→                    ?.takeWhile { it != startOfFunctionLiteral }
158→                    ?.none { it.isWhiteSpaceWithNewline() }
159→                    ?: false
160→            }
