191→    private fun intendedIndent(child: ASTNode): String =
192→        when {
193→            // IDEA quirk:
194→            // fun <
195→            //     T,
196→            //     R> test(
197→            //     param1: T
198→            //     param2: R
199→            // )
200→            // instead of
201→            // fun <
202→            //     T,
203→            //     R> test(
204→            //         param1: T
205→            //         param2: R
206→            //     )
207→            child.treeParent.hasTypeParameterListInFront() -> -1
208→
209→            else -> 0
210→        }.let {
211→            if (child.elementType == VALUE_PARAMETER) {
212→                it + 1
213→            } else {
214→                it
215→            }
216→        }.let { indentLevelFix ->
217→            val indentLevel =
218→                indentConfig
219→                    .indentLevelFrom(child.treeParent.indent(false))
220→                    .plus(indentLevelFix)
