224→    private fun wrapParameterInList(
225→        child: ASTNode,
226→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
227→        autoCorrect: Boolean,
228→    ) {
229→        when (child.elementType) {
230→            LPAR -> {
231→                val prevLeaf = child.prevLeaf()
232→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
233→                    if (child.treeParent.isFunctionTypeWrappedInNullableType()) {
234→                        return
235→                    }
236→                    emit(child.startOffset, errorMessage(child), true)
237→                    if (autoCorrect) {
238→                        prevLeaf.delete()
239→                    }
240→                }
241→            }
242→            VALUE_PARAMETER,
243→            RPAR,
244→            -> {
245→                // aiming for
246→                // ... LPAR
247→                // <line indent + indentSize> VALUE_PARAMETER...
248→                // <line indent> RPAR
249→                val intendedIndent = intendedIndent(child)
250→                val prevLeaf = child.prevLeaf()
251→                if (prevLeaf is PsiWhiteSpace) {
252→                    if (prevLeaf.getText().contains("\n")) {
253→                        // The current child is already wrapped to a new line. Checking and fixing the
254→                        // correct size of the indent is the responsibility of the IndentationRule.
255→                        return
256→                    } else {
257→                        // The current child needs to be wrapped to a newline.
258→                        emit(child.startOffset, errorMessage(child), true)
259→                        if (autoCorrect) {
260→                            // The indentation is purely based on the previous leaf only. Note that in
261→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
262→                            // determines the final indentation. But if the indent rule is disabled then the
263→                            // indent of this rule is kept.
264→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
265→                        }
266→                    }
267→                } else {
268→                    // Insert a new whitespace element in order to wrap the current child to a new line.
269→                    emit(child.startOffset, errorMessage(child), true)
270→                    if (autoCorrect) {
271→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
272→                    }
273→                }
274→                // Indentation of child nodes need to be fixed by the IndentationRule.
275→            }
276→        }
277→    }
