279→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
280→
281→    private fun errorMessage(node: ASTNode) =
282→        when (node.elementType) {
283→            LPAR -> """Unnecessary newline before "(""""
284→            VALUE_PARAMETER ->
285→                "Parameter should start on a newline"
286→            RPAR -> """Missing newline before ")""""
287→            else -> throw UnsupportedOperationException()
288→        }
