290→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
291→        val parent = this.treeParent
292→        val typeParameterList =
293→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
294→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
295→            } else {
296→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
297→            }
298→        val typeListNode =
299→            typeParameterList
300→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
301→                ?: return false
302→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
303→    }
304→}
