124→        // java.io.File("debug_need.txt").appendText("Node: $elementType checking needToWrap\n")
125→        return when {
126→            hasNoParameters() -> false
127→            codeStyle != ktlint_official && isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
128→            codeStyle == ktlint_official && isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression() ->
129→                false
130→            isFunctionTypeWrappedInNullableType() -> false
131→            textContains('\n') -> true
132→            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
133→            exceedsMaxLineLength() -> true
134→            else -> false
135→        }
136→    }
137→
138→    private fun ASTNode.hasNoParameters(): Boolean {
139→        require(elementType == VALUE_PARAMETER_LIST)
140→        return firstChildNode?.treeNext?.elementType == RPAR
141→    }
142→
143→    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
144→        require(elementType == VALUE_PARAMETER_LIST)
145→        return treeParent?.elementType == FUNCTION_LITERAL
146→    }
147→
148→    private fun ASTNode.isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression(): Boolean {
149→        require(elementType == VALUE_PARAMETER_LIST)
150→        return firstChildLeafOrSelf()
151→            .let { startOfFunctionLiteral ->
152→                treeParent
153→                    ?.takeIf { it.elementType == FUNCTION_LITERAL }
154→                    ?.prevCodeLeaf()
155→                    ?.takeIf { it.treeParent.elementType == ElementType.VALUE_ARGUMENT_LIST }
156→                    ?.takeIf { it.treeParent.treeParent.elementType == ElementType.CALL_EXPRESSION }
157→                    ?.leaves()
158→                    ?.takeWhile { it != startOfFunctionLiteral }
159→                    ?.none { it.isWhiteSpaceWithNewline() }
160→                    ?: false
161→            }
162→    }
163→
164→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
165→        require(elementType == VALUE_PARAMETER_LIST)
166→        return treeParent.elementType.toString() == "FUNCTION_TYPE" && treeParent?.treeParent?.elementType.toString() == "NULLABLE_TYPE"
167→    }
168→
169→    private fun ASTNode.containsAnnotatedParameter(): Boolean {
170→        require(elementType == VALUE_PARAMETER_LIST)
171→        return this.children()
172→            .filter { it.elementType == VALUE_PARAMETER }
173→            .any { it.isAnnotated() }
174→    }
175→
176→    private fun ASTNode.isAnnotated() =
177→        findChildByType(ElementType.MODIFIER_LIST)
178→            ?.children()
179→            .orEmpty()
180→            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
181→
182→    private fun wrapParameterList(
183→        node: ASTNode,
184→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
185→        autoCorrect: Boolean,
186→    ) {
187→        node
188→            .children()
189→            .forEach { child -> wrapParameterInList(child, emit, autoCorrect) }
190→    }
191→
192→    private fun intendedIndent(child: ASTNode): String =
193→        when {
194→            // IDEA quirk:
195→            // fun <
196→            //     T,
197→            //     R> test(
198→            //     param1: T
199→            //     param2: R
200→            // )
201→            // instead of
202→            // fun <
203→            //     T,
204→            //     R> test(
205→            //         param1: T
206→            //         param2: R
207→            //     )
208→            child.treeParent.hasTypeParameterListInFront() -> -1
209→
210→            else -> 0
211→        }.let {
212→            if (child.elementType == VALUE_PARAMETER) {
213→                it + 1
214→            } else {
215→                it
216→            }
217→        }.let { indentLevelFix ->
218→            val indentLevel =
219→                indentConfig
220→                    .indentLevelFrom(child.treeParent.indent(false))
221→                    .plus(indentLevelFix)
222→            "\n" + indentConfig.indent.repeat(indentLevel)
223→        }
224→
225→    private fun wrapParameterInList(
226→        child: ASTNode,
227→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
228→        autoCorrect: Boolean,
229→    ) {
230→        when (child.elementType) {
231→            LPAR -> {
232→                val prevLeaf = child.prevLeaf()
233→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
234→                    emit(child.startOffset, errorMessage(child), true)
235→                    if (autoCorrect) {
236→                        prevLeaf.delete()
237→                    }
238→                }
239→            }
240→            VALUE_PARAMETER,
241→            RPAR,
242→            -> {
243→                // aiming for
244→                // ... LPAR
245→                // <line indent + indentSize> VALUE_PARAMETER...
246→                // <line indent> RPAR
247→                val intendedIndent = intendedIndent(child)
248→                val prevLeaf = child.prevLeaf()
249→                if (prevLeaf is PsiWhiteSpace) {
250→                    if (prevLeaf.getText().contains("\n")) {
251→                        // The current child is already wrapped to a new line. Checking and fixing the
252→                        // correct size of the indent is the responsibility of the IndentationRule.
253→                        return
254→                    } else {
255→                        // The current child needs to be wrapped to a newline.
256→                        emit(child.startOffset, errorMessage(child), true)
257→                        if (autoCorrect) {
258→                            // The indentation is purely based on the previous leaf only. Note that in
259→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
260→                            // determines the final indentation. But if the indent rule is disabled then the
261→                            // indent of this rule is kept.
262→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
263→                        }
264→                    }
265→                } else {
266→                    // Insert a new whitespace element in order to wrap the current child to a new line.
267→                    emit(child.startOffset, errorMessage(child), true)
268→                    if (autoCorrect) {
269→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
270→                    }
271→                }
272→                // Indentation of child nodes need to be fixed by the IndentationRule.
273→            }
274→        }
275→    }
276→
277→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
278→
279→    private fun errorMessage(node: ASTNode) =
280→        when (node.elementType) {
281→            LPAR -> """Unnecessary newline before "(""""
282→            VALUE_PARAMETER ->
283→                "Parameter should start on a newline"
284→            RPAR -> """Missing newline before ")""""
285→            else -> throw UnsupportedOperationException()
286→        }
287→
288→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
289→        val parent = this.treeParent
290→        val typeParameterList =
291→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
292→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
293→            } else {
294→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
295→            }
296→        val typeListNode =
297→            typeParameterList
298→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
299→                ?: return false
300→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
301→    }
302→}
303→
304→public val PARAMETER_LIST_WRAPPING_RULE_ID: RuleId = ParameterListWrappingRule().ruleId
